380	impl<C: StreamableHttpClient> Worker for StreamableHttpClientWorker<C> {
381	    type Role = RoleClient;
382	    type Error = StreamableHttpError<C::Error>;
383	    fn err_closed() -> Self::Error {
384	        StreamableHttpError::TransportChannelClosed
385	    }
386	    fn err_join(e: tokio::task::JoinError) -> Self::Error {
387	        StreamableHttpError::TokioJoinError(e)
388	    }
389	    fn config(&self) -> super::worker::WorkerConfig {
390	        super::worker::WorkerConfig {
391	            name: Some("StreamableHttpClientWorker".into()),
392	            channel_buffer_capacity: self.config.channel_buffer_capacity,
393	        }
394	    }
395	    async fn run(
396	        self,
397	        mut context: super::worker::WorkerContext<Self>,
398	    ) -> Result<(), WorkerQuitReason<Self::Error>> {
399	        let channel_buffer_capacity = self.config.channel_buffer_capacity;
400	        let (sse_worker_tx, mut sse_worker_rx) =
401	            tokio::sync::mpsc::channel::<ServerJsonRpcMessage>(channel_buffer_capacity);
402	        let config = self.config.clone();
403	        let transport_task_ct = context.cancellation_token.clone();
404	        let _drop_guard = transport_task_ct.clone().drop_guard();
405	        let WorkerSendRequest {
406	            responder,
407	            message: initialize_request,
408	        } = context.recv_from_handler().await?;
409	        let saved_init_request = initialize_request.clone();
410	        let (message, session_id) = match self
411	            .client
412	            .post_message(
413	                config.uri.clone(),
414	                initialize_request,
415	                None,
416	                config.auth_header.clone(),
417	                config.custom_headers.clone(),
418	            )
419	            .await
420	        {
421	            Ok(res) => {
422	                let _ = responder.send(Ok(()));
423	                res.expect_initialized::<C::Error>().await.map_err(
424	                    WorkerQuitReason::fatal_context("process initialize response"),
425	                )?
426	            }
427	            Err(err) => {
428	                let msg = format!("{:?}", err);
429	                let _ = responder.send(Err(err));
430	                return Err(WorkerQuitReason::fatal(
431	                    StreamableHttpError::TransportChannelClosed,
432	                    msg,
433	                ));
434	            }
435	        };
436	        let mut session_id: Option<Arc<str>> = if let Some(session_id) = session_id {
437	            Some(session_id.into())
438	        } else {
439	            if !self.config.allow_stateless {
440	                return Err(WorkerQuitReason::fatal(
441	                    StreamableHttpError::<C::Error>::MissingSessionIdInResponse,
442	                    "process initialize response",
443	                ));
444	            }
445	            None
446	        };
447	        // Extract the negotiated protocol version from the init response
448	        // and build a custom headers map that includes MCP-Protocol-Version
449	        // for all subsequent HTTP requests (per MCP 2025-06-18 spec).
450	        let mut protocol_headers = {
451	            let mut headers = config.custom_headers.clone();
452	            if let ServerJsonRpcMessage::Response(response) = &message {
453	                if let ServerResult::InitializeResult(init_result) = &response.result {
454	                    if let Ok(hv) = HeaderValue::from_str(init_result.protocol_version.as_str()) {
455	                        // HeaderName::from_static requires lowercase
456	                        headers.insert(HeaderName::from_static("mcp-protocol-version"), hv);
457	                    }
458	                }
459	            }
460	            headers
461	        };
462	
463	        // Store session info for cleanup when run() exits (not spawned, so cleanup completes before close() returns)
464	        let mut session_cleanup_info = session_id.as_ref().map(|sid| SessionCleanupInfo {
465	            client: self.client.clone(),
466	            uri: config.uri.clone(),
467	            session_id: sid.clone(),
468	            auth_header: config.auth_header.clone(),
469	            protocol_headers: protocol_headers.clone(),
470	        });
471	
472	        context.send_to_handler(message).await?;
473	        let initialized_notification = context.recv_from_handler().await?;
474	        // expect a initialized response
475	        self.client
476	            .post_message(
477	                config.uri.clone(),
478	                initialized_notification.message,
479	                session_id.clone(),
480	                config.auth_header.clone(),
481	                protocol_headers.clone(),
482	            )
483	            .await
484	            .map_err(WorkerQuitReason::fatal_context(
485	                "send initialized notification",
486	            ))?
487	            .expect_accepted_or_json::<C::Error>()
488	            .map_err(WorkerQuitReason::fatal_context(
489	                "process initialized notification response",
490	            ))?;
491	        let _ = initialized_notification.responder.send(Ok(()));
492	        #[allow(clippy::large_enum_variant)]
493	        enum Event<W: Worker, E: std::error::Error + Send + Sync + 'static> {
494	            ClientMessage(WorkerSendRequest<W>),
495	            ServerMessage(ServerJsonRpcMessage),
496	            StreamResult(Result<(), StreamableHttpError<E>>),
497	        }
498	        let mut streams = tokio::task::JoinSet::new();
499	        if let Some(session_id) = &session_id {
500	            let client = self.client.clone();
501	            let uri = config.uri.clone();
502	            let session_id = session_id.clone();
503	            let auth_header = config.auth_header.clone();
504	            let retry_config = self.config.retry_config.clone();
505	            let sse_worker_tx = sse_worker_tx.clone();
506	            let transport_task_ct = transport_task_ct.clone();
507	            let config_uri = config.uri.clone();
508	            let config_auth_header = config.auth_header.clone();
509	            let spawn_headers = protocol_headers.clone();
510	
511	            streams.spawn(async move {
512	                match client
513	                    .get_stream(
514	                        uri.clone(),
515	                        session_id.clone(),
516	                        None,
517	                        auth_header.clone(),
518	                        spawn_headers.clone(),
519	                    )
520	                    .await
521	                {
522	                    Ok(stream) => {
523	                        let sse_stream = SseAutoReconnectStream::new(
524	                            stream,
525	                            StreamableHttpClientReconnect {
526	                                client: client.clone(),
527	                                session_id: session_id.clone(),
528	                                uri: config_uri,
529	                                auth_header: config_auth_header,
530	                                custom_headers: spawn_headers,
531	                            },
532	                            retry_config,
533	                        );
534	                        Self::execute_sse_stream(
535	                            sse_stream,
536	                            sse_worker_tx,
537	                            false,
538	                            transport_task_ct.child_token(),
539	                        )
540	                        .await
541	                    }
542	                    Err(StreamableHttpError::ServerDoesNotSupportSse) => {
543	                        tracing::debug!("server doesn't support sse, skip common stream");
544	                        Ok(())
545	                    }
546	                    Err(e) => {
547	                        // fail to get common stream
548	                        tracing::error!("fail to get common stream: {e}");
549	                        Err(e)
550	                    }
551	                }
552	            });
553	        }
554	        // Main event loop - capture exit reason so we can do cleanup before returning
555	        let loop_result: Result<(), WorkerQuitReason<Self::Error>> = 'main_loop: loop {
556	            let event = tokio::select! {
557	                _ = transport_task_ct.cancelled() => {
558	                    tracing::debug!("cancelled");
559	                    break 'main_loop Err(WorkerQuitReason::Cancelled);
560	                }
561	                message = context.recv_from_handler() => {
562	                    match message {
563	                        Ok(msg) => Event::ClientMessage(msg),
564	                        Err(e) => break 'main_loop Err(e),
565	                    }
566	                },
567	                message = sse_worker_rx.recv() => {
568	                    let Some(message) = message else {
569	                        tracing::trace!("transport dropped, exiting");
570	                        break 'main_loop Err(WorkerQuitReason::HandlerTerminated);
571	                    };
572	                    Event::ServerMessage(message)
573	                },
574	                terminated_stream = streams.join_next(), if !streams.is_empty() => {
575	                    match terminated_stream {
576	                        Some(result) => {
577	                            Event::StreamResult(result.map_err(StreamableHttpError::TokioJoinError).and_then(std::convert::identity))
578	                        }
579	                        None => {
580	                            continue
581	                        }
582	                    }
583	                }
584	            };
585	            match event {
586	                Event::ClientMessage(send_request) => {
587	                    let WorkerSendRequest { message, responder } = send_request;
588	                    // Pass a clone to the first attempt so `message` is retained for a
589	                    // potential re-init retry. `post_message` takes ownership and the
590	                    // trait cannot be changed, so the clone is unavoidable.
591	                    let response = self
592	                        .client
593	                        .post_message(
594	                            config.uri.clone(),
595	                            message.clone(),
596	                            session_id.clone(),
597	                            config.auth_header.clone(),
598	                            protocol_headers.clone(),
599	                        )
600	                        .await;
601	                    let send_result = match response {
602	                        Err(StreamableHttpError::SessionExpired) => {
603	                            // The server discarded the session (HTTP 404). Perform a
604	                            // fresh handshake once and replay the original message.
605	                            tracing::info!(
606	                                "session expired (HTTP 404), attempting transparent re-initialization"
607	                            );
608	                            match Self::perform_reinitialization(
609	                                self.client.clone(),
610	                                saved_init_request.clone(),
611	                                config.uri.clone(),
612	                                config.auth_header.clone(),
613	                                config.custom_headers.clone(),
614	                            )
615	                            .await
616	                            {
617	                                Ok((new_session_id, new_protocol_headers)) => {
618	                                    // Old streams hold the stale session ID; abort them
619	                                    // so the new standalone SSE stream takes over.
620	                                    streams.abort_all();
621	
622	                                    session_id = new_session_id;
623	                                    protocol_headers = new_protocol_headers;
624	                                    session_cleanup_info =
625	                                        session_id.as_ref().map(|sid| SessionCleanupInfo {
626	                                            client: self.client.clone(),
627	                                            uri: config.uri.clone(),
628	                                            session_id: sid.clone(),
629	                                            auth_header: config.auth_header.clone(),
630	                                            protocol_headers: protocol_headers.clone(),
631	                                        });
632	
633	                                    if let Some(new_sid) = &session_id {
634	                                        let client = self.client.clone();
635	                                        let uri = config.uri.clone();
636	                                        let new_sid = new_sid.clone();
637	                                        let auth_header = config.auth_header.clone();
638	                                        let retry_config = self.config.retry_config.clone();
639	                                        let sse_tx = sse_worker_tx.clone();
640	                                        let task_ct = transport_task_ct.clone();
641	                                        let config_uri = config.uri.clone();
642	                                        let config_auth = config.auth_header.clone();
643	                                        let spawn_headers = protocol_headers.clone();
644	                                        streams.spawn(async move {
645	                                            match client
646	                                                .get_stream(
647	                                                    uri,
648	                                                    new_sid.clone(),
649	                                                    None,
650	                                                    auth_header.clone(),
651	                                                    spawn_headers.clone(),
652	                                                )
653	                                                .await
654	                                            {
655	                                                Ok(stream) => {
656	                                                    let sse_stream = SseAutoReconnectStream::new(
657	                                                        stream,
658	                                                        StreamableHttpClientReconnect {
659	                                                            client: client.clone(),
660	                                                            session_id: new_sid,
661	                                                            uri: config_uri,
662	                                                            auth_header: config_auth,
663	                                                            custom_headers: spawn_headers,
664	                                                        },
665	                                                        retry_config,
666	                                                    );
667	                                                    Self::execute_sse_stream(
668	                                                        sse_stream,
669	                                                        sse_tx,
670	                                                        false,
671	                                                        task_ct.child_token(),
672	                                                    )
673	                                                    .await
674	                                                }
675	                                                Err(StreamableHttpError::ServerDoesNotSupportSse) => {
676	                                                    tracing::debug!(
677	                                                        "server doesn't support sse after re-init"
678	                                                    );
679	                                                    Ok(())
680	                                                }
681	                                                Err(e) => {
682	                                                    tracing::error!(
683	                                                        "fail to get common stream after re-init: {e}"
684	                                                    );
685	                                                    Err(e)
686	                                                }
687	                                            }
688	                                        });
689	                                    }
