691	                                    let retry_response = self
692	                                        .client
693	                                        .post_message(
694	                                            config.uri.clone(),
695	                                            message,
696	                                            session_id.clone(),
697	                                            config.auth_header.clone(),
698	                                            protocol_headers.clone(),
699	                                        )
