777	                                    sse_worker_tx.clone(),
778	                                    true,
779	                                    transport_task_ct.child_token(),
780	                                ));
781	                            } else {
782	                                let sse_stream = SseAutoReconnectStream::never_reconnect(
783	                                    stream,
784	                                    StreamableHttpError::<C::Error>::UnexpectedEndOfStream,
785	                                );
786	                                streams.spawn(Self::execute_sse_stream(
787	                                    sse_stream,
788	                                    sse_worker_tx.clone(),
789	                                    true,
790	                                    transport_task_ct.child_token(),
791	                                ));
792	                            }
793	                            tracing::trace!("got new sse stream");
794	                            Ok(())
795	                        }
796	                    };
797	                    let _ = responder.send(send_result);
798	                }
799	                Event::ServerMessage(json_rpc_message) => {
800	                    // send the message to the handler
801	                    if let Err(e) = context.send_to_handler(json_rpc_message).await {
802	                        break 'main_loop Err(e);
803	                    }
804	                }
805	                Event::StreamResult(result) => {
