816	        // Cleanup session before returning (ensures close() waits for session deletion)
817	        // Use a timeout to prevent indefinite hangs if the server is unresponsive
818	        if let Some(cleanup) = session_cleanup_info {
819	            const SESSION_CLEANUP_TIMEOUT: std::time::Duration = std::time::Duration::from_secs(5);
820	            let cleanup_session_id = cleanup.session_id.clone();
821	            match tokio::time::timeout(
822	                SESSION_CLEANUP_TIMEOUT,
823	                cleanup.client.delete_session(
824	                    cleanup.uri,
825	                    cleanup.session_id,
826	                    cleanup.auth_header,
827	                    cleanup.protocol_headers,
828	                ),
829	            )
830	            .await
831	            {
832	                Ok(Ok(_)) => {
833	                    tracing::info!(
834	                        session_id = cleanup_session_id.as_ref(),
