836	                    )
837	                }
838	                Ok(Err(StreamableHttpError::ServerDoesNotSupportDeleteSession)) => {
839	                    tracing::info!(
840	                        session_id = cleanup_session_id.as_ref(),
841	                        "server doesn't support delete session"
842	                    )
843	                }
844	                Ok(Err(e)) => {
845	                    tracing::error!(
846	                        session_id = cleanup_session_id.as_ref(),
847	                        "fail to delete session: {e}"
848	                    );
849	                }
850	                Err(_elapsed) => {
851	                    tracing::warn!(
852	                        session_id = cleanup_session_id.as_ref(),
853	                        "session cleanup timed out after {:?}",
854	                        SESSION_CLEANUP_TIMEOUT
855	                    );
856	                }
857	            }
858	        }
859	
860	        loop_result
861	    }
